  const ones = ['', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine'];
  const teens = ['ten', 'eleven', 'twelve', 'thirteen', 'fourteen', 'fifteen', 'sixteen', 'seventeen', 'eighteen', 'nineteen'];
  const tens = ['', '', 'twenty', 'thirty', 'forty', 'fifty', 'sixty', 'seventy', 'eighty', 'ninety'];
  function twoDigit(n) {
    if (n === 0) return '';
    if (n < 10) return ones[n];
    if (n < 20) return teens[n - 10];
    const t = tens[Math.floor(n / 10)];
    const o = ones[n % 10];
    return o ? t + '-' + o : t;
  }
  const century = Math.floor(y / 100);
  const remainder = y % 100;
  if (y >= 2000 && y <= 2009) {
    return remainder === 0 ? 'two thousand' : 'two thousand ' + twoDigit(remainder);
  }
  return twoDigit(century) + ' ' + twoDigit(remainder);
}

const yearPronunciations = {};
for (let y = 1990; y <= 2030; y++) yearPronunciations[String(y)] = yearToSpokenWords(y);

// Merge precedence: year < industry < client (client wins on conflict)
const pronunciationLibrary = { ...yearPronunciations, ...industryPronunciations, ...verticalPronunciations, ...basePromptPronunciations, ...clientPronunciations };

// Sort keys by length DESC so multi-word phrases match before single words
const sortedKeys = Object.keys(pronunciationLibrary).sort((a, b) => b.length - a.length);

function escapeRegex(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function applyPronunciations(text) {
  if (!text || typeof text !== 'string') return text;
  let result = text;
  for (const key of sortedKeys) {
    const re = new RegExp('\\b' + escapeRegex(key) + '\\b', 'gi');
    result = result.replace(re, pronunciationLibrary[key]);
  }
  return result;
}

// Tokenize a string into "words" — split on whitespace, strip surrounding punctuation
function tokenize(text) {
  if (!text) return [];
  return text.split(/\s+/)
    .map(w => w.replace(/^[^\w\-']+|[^\w\-']+$/g, ''))
    .filter(w => w.length > 0);
}

// Sweep original tokens; for each pronunciation match emit phonetic tokens
// where the first one carries the full display phrase and subsequent ones get "".
function buildDisplayTokens(originalText) {
  const origTokens = tokenize(originalText);
  const tokens = [];
  let i = 0;
  while (i < origTokens.length) {
    let matched = false;
    for (const key of sortedKeys) {
      const keyToks = tokenize(key);
      if (keyToks.length === 0) continue;
      if (i + keyToks.length > origTokens.length) continue;
      let ok = true;
      for (let j = 0; j < keyToks.length; j++) {
        if (origTokens[i + j].toLowerCase() !== keyToks[j].toLowerCase()) { ok = false; break; }
      }
      if (!ok) continue;
      const displayPhrase = origTokens.slice(i, i + keyToks.length).join(' ');
      const phoneticTokens = tokenize(pronunciationLibrary[key]);
      for (let p = 0; p < phoneticTokens.length; p++) {
        tokens.push({ phonetic: phoneticTokens[p], display: p === 0 ? displayPhrase : '' });
      }
      i += keyToks.length;
      matched = true;
      break;
    }
    if (!matched) {
      tokens.push({ phonetic: origTokens[i], display: origTokens[i] });
      i += 1;
    }
  }
  return tokens;
}

// ─── Apply ─────────────────────────────────────────────────────
const originalFull = script.full_script
  || [script.hook, ...(Array.isArray(script.segments) ? script.segments : []), script.cta].filter(Boolean).join(' ');

