  segments: original.segments.map(s => applyPronunciations(s)),
  cta: applyPronunciations(original.cta),
  full_script: applyPronunciations(original.full_script)
};

const display_tokens = buildDisplayTokens(original.full_script);

// ═══════════════════════════════════════════════════════════════
// Backward-compat: top-level script.{hook,segments,cta,full_script}
// remains the phonetic version (what TTS reads) so existing consumers
// (e.g. [03] Parse 11Labs Response char-position mapping) stay working.
