// ENRICH VEHICLE FEATURES
// Apply industry-specific feature enrichment from DB
// ═══════════════════════════════════════════════════════════════

const config = $json;
let vehicles = config.vehicles || [];

// Get industry feature enrichment config
const industryConfig = config.industry_config || {};
const featureEnrichment = industryConfig.feature_enrichment || {};

// Parse if string (JSONB from Postgres)
const enrichmentConfig = typeof featureEnrichment === 'string'
  ? JSON.parse(featureEnrichment)
  : featureEnrichment;

// Get reliable brands from industry config (or empty array)
const reliableBrands = enrichmentConfig.reliable_brands || [];

console.log('🔧 Feature enrichment config:', JSON.stringify(enrichmentConfig));
console.log('🚗 Reliable brands:', reliableBrands.join(', ') || 'none configured');

// Enrich each vehicle
vehicles = vehicles.map(vehicle => {
  let features = [...(vehicle.features || [])];

  const mileage = parseInt(vehicle.mileage) || 0;
  const year = parseInt(vehicle.year) || 2020;
  const currentYear = new Date().getFullYear();
  const age = currentYear - year;

  // ────────────────────────────────────────────────────────���────
  // LOW MILEAGE (relative to age)
  // ─────────────────────────────────────────────────────────────
  const expectedMileage = age * 12000;
  if (mileage > 0 && mileage < expectedMileage * 0.6) {
    features.unshift('Low Mileage');
  }

  // ─────────────────────────────────────────────────────────────
  // HYBRID/ELECTRIC POWER
  // ─────────────────────────────────────────────────────────────
  const engine = (vehicle.engine || '').toLowerCase();
  if (engine.includes('hybrid') || engine.includes('electric')) {
    features.unshift('Hybrid Power');
  } else if (engine.includes('4-cyl') || engine.includes('turbo')) {
    // Only add if not already there
    if (!features.includes('Great Gas Mileage')) {
      features.push('Great Gas Mileage');
    }
  }

  // ─────────────────────────────────────────────────────────────
  // AWD/4WD
  // ─────────────────────────────────────────────────────────────
  const drivetrain = (vehicle.drivetrain || '').toLowerCase();
  if (drivetrain.includes('awd') || drivetrain.includes('4wd') || drivetrain.includes('4x4')) {
    if (!features.includes('All-Wheel Drive')) {
      features.push('All-Wheel Drive');
    }
  }

  // ─────────────────────────────────────────────────────────────
  // RELIABLE BRANDS (from industry.feature_enrichment.reliable_brands)
  // ─────────────────────────────────────────────────────────────
  const make = (vehicle.make || '').toLowerCase();
  if (reliableBrands.length > 0 && reliableBrands.includes(make)) {
    if (!features.includes('Reliable Brand')) {
      features.push('Reliable Brand');
    }
  }

  // Ensure at least one feature
  if (features.length === 0) {
    features.push('Great Condition');
  }

  return {
    ...vehicle,
    features: features
  };
});

console.log('✅ Enriched features for', vehicles.length, 'vehicles');
vehicles.forEach((v, i) => {
  console.log(`  ${i + 1}. ${v.year} ${v.make} ${v.model}: ${v.features.join(', ')}`);
});

return [{
  json: {
    ...config,
    vehicles
  }
}];

