  sceneSlugs = typeof row.scene_slugs === 'string' ? JSON.parse(row.scene_slugs) : row.scene_slugs;
}

console.log('Video recipe: ' + videoRecipeSlug + ' (' + sceneSlugs.length + ' scenes)');

// Get timing config
const timing = {
  hook_words: timingDefaults.hook_words || 12,
  segment_words: timingDefaults.segment_words || 15,
  cta_words: timingDefaults.cta_words || 12
};

// Get items from config (processed or raw)
const items = config.processed_items || config.vehicles || [];
const themePack = config.theme_pack || null;

// Build scene descriptions for Claude
const sceneInstructions = sceneSlugs.map((slug, idx) => {
  const recipe = sceneRecipes[slug];
  if (!recipe) throw new Error('Scene recipe not found: ' + slug);
  const def = recipe.definition;

  let wordLimit;
  if (recipe.scene_type === 'hook') wordLimit = timing.hook_words;
  else if (recipe.scene_type === 'cta') wordLimit = timing.cta_words;
  else {
    // Body scenes: segment words × item count (or just segment words if no items)
    const itemCount = def.items ? Math.min(items.length, def.items.max || 5) : 0;
    wordLimit = itemCount > 0 ? timing.segment_words * itemCount : timing.segment_words;
  }

  let desc = 'Scene ' + (idx + 1) + ': "' + recipe.name + '" (type: ' + recipe.scene_type + ')';
  desc += '\n  scene_slug: "' + slug + '"';
  desc += '\n  Word limit: ~' + wordLimit + ' words for audio_text';

  if (def.headline && def.headline.allowed) {
    desc += '\n  Headline: Required. Max ' + (def.headline.max_lines || 2) + ' lines. Short, punchy phrases (2-4 words each). Return as array of strings.';
  } else {
    desc += '\n  Headline: null (not used in this scene)';
  }

  if (def.items && items.length > 0) {
    const itemCount = Math.min(items.length, def.items.max || 5);
    desc += '\n  Items: ' + itemCount + ' inventory items will be shown. Mention each in the audio naturally.';
    desc += '\n  Available items:';
    items.slice(0, itemCount).forEach((item, i) => {
      const title = item.title || (item.year + ' ' + item.make + ' ' + item.model) || 'Item ' + (i + 1);
      const price = item.price || '';
      desc += '\n    ' + (i + 1) + '. ' + title + (price ? ' — ' + price : '');
    });
  } else {
    desc += '\n  Items: none';
  }

  if (def.avatar && def.avatar.required) {
    desc += '\n  Avatar: visible (the presenter is on screen)';
  } else {
    desc += '\n  Avatar: not visible';
  }

  if (def.contact) {
    desc += '\n  Contact info is displayed — include a call-to-action';
  }

  return desc;
}).join('\n\n');

// Build user prompt
const userPrompt = \`Write a video ad script following this exact scene structure.

