      "audio_text": "<the script text for this scene — spoken by the presenter>",
      "headline_text": <["LINE 1", "LINE 2"] or null if headline not used>,
      "background_url": null,
      "items": [<array of {photo_url, title, price, mileage} for body scenes with items, empty array otherwise>]
    }
  ],
