// Parse JSON response
const cleanText = apiResponse
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleanText);
} catch (error) {
  throw new Error('Failed to parse scene script response: ' + error.message + '\nRaw: ' + cleanText.substring(0, 200));
}

// Validate scenes array
if (!parsed.scenes || !Array.isArray(parsed.scenes)) {
  throw new Error('Script response missing scenes array');
}

const expectedSlugs = config._scene_slugs;
if (parsed.scenes.length !== expectedSlugs.length) {
  throw new Error('Expected ' + expectedSlugs.length + ' scenes but got ' + parsed.scenes.length);
}

// Validate each scene and ensure background_url field exists
const scenes = parsed.scenes.map((scene, idx) => {
  if (scene.scene_slug !== expectedSlugs[idx]) {
    console.log('WARNING: Scene ' + idx + ' slug mismatch: expected ' + expectedSlugs[idx] + ', got ' + scene.scene_slug);
    scene.scene_slug = expectedSlugs[idx];
  }

  // Ensure all required fields
  return {
    scene_slug: scene.scene_slug,
    scene_type: scene.scene_type || config._scene_recipes[scene.scene_slug]?.scene_type || 'body',
    position: idx,
    audio_text: scene.audio_text || '',
    headline_text: scene.headline_text || null,
    background_url: scene.background_url || null,
    items: scene.items || []
  };
});

// Build full_script by concatenating all audio_text (for TTS)
const fullScript = scenes.map(s => s.audio_text).join(' ');

// Build backward-compatible script object
const script = {
  scenes: scenes,
  full_script: fullScript,
  thumbnail_text: parsed.thumbnail_text || '',
  // Backward compatibility: map to hook/segments/cta
  hook: scenes.find(s => s.scene_type === 'hook')?.audio_text || '',
  segments: scenes.filter(s => s.scene_type === 'body').map(s => s.audio_text),
  cta: scenes.find(s => s.scene_type === 'cta')?.audio_text || ''
};

console.log('Parsed ' + scenes.length + ' scenes. Full script: ' + fullScript.length + ' chars');
console.log('Thumbnail: ' + script.thumbnail_text);

// Strip prompt data, return clean config + script
const { system_prompt, messages, _scene_pipeline, ...cleanConfig } = config;

return [{
  json: {
    ...cleanConfig,
    script: script,
    _scene_pipeline: true
  }
}];

