- Banned phrases: ${JSON.stringify(themePack.banned_phrases)}`;
} else {
  themeSection = 'THEME: None provided';
}

// Map processed_items to vehicles format (for compatibility with TEMP_001)
const vehicles = processedItems.map(item => ({
  vin: item.vin,
  year: item.year,
  make: item.make,
  model: item.model,
  trim: item.trim,
  mileage: item.mileage,
  price: item.price,
  image_url: item.photo_url,
  features: item.equipment_highlights || [],
  // Additional processed data
  mileage_category: item.mileage_category,
  equipment_summary: item.equipment_summary,
  days_on_lot: item.days_on_lot
}));

// Spotlight-specific data: stored inside processedItems[0] by [Process Spotlight Asset]
const firstItem = processedItems[0] || {};
const verifiedFeatures = firstItem.verified_features || {};
const selectedPhotos = firstItem.selected_photos || {};
const allImages = firstItem.all_images || [];

console.log('═══════════════════════════════════════════════════════════════');
console.log('PREPARE SCRIPT CONTEXT (FROM ASSET)');
console.log('═══════════════════════════════════════════════════════════════');
console.log(`Asset ID: ${asset.id}`);
console.log(`Template: ${asset.template_code}`);
console.log(`Theme Mode: ${asset.theme_mode}`);
console.log(`Items: ${processedItems.length}`);
console.log(`Theme Pack: ${themePack ? themePack.theme_name : 'none'}`);
console.log(`Timing: ${timing.code}`);
console.log(`Client: ${asset.client_name}`);
console.log(`Spotlight data: verified_features=${Object.keys(verifiedFeatures).length} categories, selected_photos=${Object.keys(selectedPhotos).length} photos, all_images=${allImages.length}`);
console.log('═══════════════════════════════════════════════════════════════');

return [{
  json: {
    // Asset info
    asset_id: asset.id,
    template_id: asset.template_id,
    template_code: asset.template_code,
    theme_mode: asset.theme_mode,

    // Timing
    timing,
    script_length: asset.target_length || 'standard',

    // Theme
    theme_pack: themePack,
    theme_section: themeSection,
    theme_mode_rules: themeModeRules,

    // Items (processed)
    vehicles,
    items: processedItems,
    item_count: processedItems.length,

    // Client info
    client_id: asset.client_id,
    client_name: asset.client_name,
    client_location: asset.client_location || '',

    // Other asset data
    avatars: asset.avatars,
    music_id: asset.music_id,
    background_id: asset.background_id,

    // Spotlight-specific data (from processedItems[0])
    verified_features: verifiedFeatures,
    selected_photos: selectedPhotos,
    all_images: allImages
  }
}];

// Extract config from the processed asset data
// Matches the shape that Pass Config provides for the orchestration path
const asset = $('Fetch Processed Asset').first().json;
const avatars = typeof asset.avatars === 'string'
  ? JSON.parse(asset.avatars)
  : (asset.avatars || []);

// Map frontend target_length to timing_defaults codes
// Frontend uses: brief, standard, detailed
// DB timing_defaults uses: quick, standard, detailed
const lengthMap = { brief: 'quick', standard: 'standard', detailed: 'detailed' };
const script_length = lengthMap[asset.target_length] || asset.target_length || 'standard';

return [{
  json: {
    client_id: asset.client_id,
    template_id: asset.template_code || asset.template_id,
    script_length: script_length,
    avatars: avatars,
    business_name: asset.client_name,
    client_name: asset.client_name,
    _source: 'asset',
    video_recipe_id: asset.video_recipe_id || undefined
  }
}];

// Resolve config from whichever path is active
// Orchestration path: Pass Config ran
// Webhook/Asset path: Prepare Asset Config ran
let config;
try {
  config = $('Pass Config').first().json;
  config._source = config._source || 'orchestration';
} catch (e) {
  config = $('Prepare Asset Config').first().json;
}
return [{ json: config }];

// Transform pre-processed data from [Process] sub-workflows into prompt-ready format
// Same output shape as "Prepare Script Context (Asset)"

var config = $json;
var processedItems = config.processed_items || [];
var themePack = config.theme_pack || null;

// Map processed_items to vehicles format (for TEMP_001/002 compatibility)
var vehicles = processedItems.map(function(item) {
  return {
    vin: item.vin,
    year: item.year,
    make: item.make,
    model: item.model,
    trim: item.trim,
    mileage: item.mileage,
    price: item.price,
    image_url: item.photo_url || item.primary_image_url || "",
    features: item.equipment_highlights || [],
    mileage_category: item.mileage_category || "",
    equipment_summary: item.equipment_summary || "",
    days_on_lot: item.days_on_lot || 0
  };
});

// Spotlight-specific data (stored in processedItems[0] by Process Spotlight Asset)
var firstItem = processedItems[0] || {};
var verifiedFeatures = firstItem.verified_features || {};
var selectedPhotos = firstItem.selected_photos || {};
var allImages = firstItem.all_images || [];

// Derive template_code from template_id for downstream routing
var templateId = config.template_id || "";
var templateCode = "";
if (templateId.indexOf("multi-item") !== -1) templateCode = "MULTI-ITEM";
else if (templateId.indexOf("spotlight") !== -1) templateCode = "SPOTLIGHT";
else if (templateId.indexOf("educational") !== -1) templateCode = "EDUCATIONAL";
else templateCode = templateId.toUpperCase();

console.log("[Build Context from Processed Data] Items: " + processedItems.length + ", Template: " + templateCode + ", Theme: " + (themePack ? (themePack.theme_name || "unnamed") : "none"));

return [{
  json: {
    // Config passthrough (timing, theme_section, theme_pack already set)
    ...config,

    // Template info
    template_code: templateCode,

    // Items (processed)
    vehicles: vehicles,
    items: processedItems,
    item_count: processedItems.length,

    // Client info (normalize naming between paths)
    client_name: config.business_name || config.client_name || "",
    client_location: config.location || config.client_location || "",

    // Spotlight-specific
    verified_features: verifiedFeatures,
    selected_photos: selectedPhotos,
    all_images: allImages
  }
}];

// Return script data to the calling workflow (sub-workflow path)
// For webhook calls, Respond to Webhook already sent the response
var parseResult = $('Parse Script Generation').first().json;
return [{ json: parseResult }];

// ═══════════════════════════════════════════════════════════════
// BUILD SCRIPT PROMPT — SCENE-BASED
// Uses scene recipes to tell Claude the exact structure needed.
// Reuses system prompt from Assemble System Prompt.
// ═══════════════════════════════════════════════════════════════

const config = $('Resolve Config').first().json;
const systemPrompt = $('Assemble System Prompt').first().json.system_prompt;
const recipeRows = $('Fetch Scene Recipes').all().map(r => r.json);
const timingDefaults = $('Fetch Timing Defaults').first().json;

// Parse scene recipe definitions
const sceneRecipes = {};
let videoRecipeSlug = '';
let sceneSlugs = [];
for (const row of recipeRows) {
  const def = typeof row.definition === 'string' ? JSON.parse(row.definition) : row.definition;
  sceneRecipes[row.slug] = {
    slug: row.slug,
    scene_type: row.scene_type,
    name: row.name,
    definition: def
  };
  videoRecipeSlug = row.video_recipe_slug;
  sceneSlugs = typeof row.scene_slugs === 'string' ? JSON.parse(row.scene_slugs) : row.scene_slugs;
}

console.log('Video recipe: ' + videoRecipeSlug + ' (' + sceneSlugs.length + ' scenes)');

// Get timing config
const timing = {
  hook_words: timingDefaults.hook_words || 12,
  segment_words: timingDefaults.segment_words || 15,
  cta_words: timingDefaults.cta_words || 12
};

// Get items from config (processed or raw)
const items = config.processed_items || config.vehicles || [];
const themePack = config.theme_pack || null;

// Build scene descriptions for Claude
const sceneInstructions = sceneSlugs.map((slug, idx) => {
  const recipe = sceneRecipes[slug];
  if (!recipe) throw new Error('Scene recipe not found: ' + slug);
  const def = recipe.definition;

  let wordLimit;
  if (recipe.scene_type === 'hook') wordLimit = timing.hook_words;
  else if (recipe.scene_type === 'cta') wordLimit = timing.cta_words;
  else {
    // Body scenes: segment words × item count (or just segment words if no items)
    const itemCount = def.items ? Math.min(items.length, def.items.max || 5) : 0;
    wordLimit = itemCount > 0 ? timing.segment_words * itemCount : timing.segment_words;
  }

  let desc = 'Scene ' + (idx + 1) + ': "' + recipe.name + '" (type: ' + recipe.scene_type + ')';
  desc += '\n  scene_slug: "' + slug + '"';
  desc += '\n  Word limit: ~' + wordLimit + ' words for audio_text';

  if (def.headline && def.headline.allowed) {
    desc += '\n  Headline: Required. Max ' + (def.headline.max_lines || 2) + ' lines. Short, punchy phrases (2-4 words each). Return as array of strings.';
  } else {
    desc += '\n  Headline: null (not used in this scene)';
  }

  if (def.items && items.length > 0) {
    const itemCount = Math.min(items.length, def.items.max || 5);
    desc += '\n  Items: ' + itemCount + ' inventory items will be shown. Mention each in the audio naturally.';
    desc += '\n  Available items:';
    items.slice(0, itemCount).forEach((item, i) => {
      const title = item.title || (item.year + ' ' + item.make + ' ' + item.model) || 'Item ' + (i + 1);
      const price = item.price || '';
      desc += '\n    ' + (i + 1) + '. ' + title + (price ? ' — ' + price : '');
    });
  } else {
    desc += '\n  Items: none';
  }

  if (def.avatar && def.avatar.required) {
    desc += '\n  Avatar: visible (the presenter is on screen)';
  } else {
    desc += '\n  Avatar: not visible';
  }

  if (def.contact) {
    desc += '\n  Contact info is displayed — include a call-to-action';
  }

  return desc;
}).join('\n\n');

// Build user prompt
const userPrompt = \`Write a video ad script following this exact scene structure.

SCENE STRUCTURE:
\${sceneInstructions}

\${themePack ? 'WEEKLY THEME: ' + (themePack.theme_name || '') + '\nDirection: ' + (themePack.theme_direction || '') + '\n' : ''}

CLIENT: \${config.business_name || 'the business'}
\${config.location ? 'LOCATION: ' + config.location : ''}
\${config.service_area ? 'SERVICE AREA: ' + config.service_area : ''}

Return ONLY valid JSON matching this exact schema:
{
  "scenes": [
    {
      "scene_slug": "<must match the scene_slug above>",
      "scene_type": "<hook|body|cta>",
      "position": <0-indexed>,
      "audio_text": "<the script text for this scene — spoken by the presenter>",
      "headline_text": <["LINE 1", "LINE 2"] or null if headline not used>,
      "background_url": null,
      "items": [<array of {photo_url, title, price, mileage} for body scenes with items, empty array otherwise>]
    }
  ],
  "thumbnail_text": "<short catchy text for video thumbnail, 3-5 words>"
}

IMPORTANT:
- Each scene's audio_text must respect the word limit specified above
- headline_text is an array of short phrases (2-4 words each), or null
- Items array should mirror the items listed above with their exact data
- background_url is always null (will be set separately)
- thumbnail_text should be attention-grabbing and relate to the hook\`;

// Build messages array for Claude
const messages = [
  { role: 'user', content: userPrompt }
];

console.log('Scene prompt built. ' + sceneSlugs.length + ' scenes, ' + items.length + ' items');

return [{
  json: {
    ...config,
    _scene_pipeline: true,
    _scene_recipes: sceneRecipes,
    _scene_slugs: sceneSlugs,
    _items: items,
    system_prompt: systemPrompt,
    messages: messages,
    model: 'claude-sonnet-4-20250514'
  }
}];

// ═══════════════════════════════════════════════════════════════
// PARSE SCRIPT — SCENE-BASED OUTPUT
// Parses Claude's response into scenes[] structure.
// Adds background_url field (null for now, populated by Planner).
// Builds full_script for TTS compatibility.
// ═══════════════════════════════════════════════════════════════

const config = $('Build Script Prompt (Scenes)').first().json;
const apiResponse = $json.content[0].text;

// Parse JSON response
const cleanText = apiResponse
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleanText);
} catch (error) {
  throw new Error('Failed to parse scene script response: ' + error.message + '\nRaw: ' + cleanText.substring(0, 200));
}

// Validate scenes array
if (!parsed.scenes || !Array.isArray(parsed.scenes)) {
  throw new Error('Script response missing scenes array');
}

const expectedSlugs = config._scene_slugs;
if (parsed.scenes.length !== expectedSlugs.length) {
  throw new Error('Expected ' + expectedSlugs.length + ' scenes but got ' + parsed.scenes.length);
}

// Validate each scene and ensure background_url field exists
const scenes = parsed.scenes.map((scene, idx) => {
  if (scene.scene_slug !== expectedSlugs[idx]) {
    console.log('WARNING: Scene ' + idx + ' slug mismatch: expected ' + expectedSlugs[idx] + ', got ' + scene.scene_slug);
    scene.scene_slug = expectedSlugs[idx];
  }

  // Ensure all required fields
  return {
    scene_slug: scene.scene_slug,
    scene_type: scene.scene_type || config._scene_recipes[scene.scene_slug]?.scene_type || 'body',
    position: idx,
    audio_text: scene.audio_text || '',
    headline_text: scene.headline_text || null,
    background_url: scene.background_url || null,
    items: scene.items || []
  };
});

// Build full_script by concatenating all audio_text (for TTS)
const fullScript = scenes.map(s => s.audio_text).join(' ');

// Build backward-compatible script object
const script = {
  scenes: scenes,
  full_script: fullScript,
  thumbnail_text: parsed.thumbnail_text || '',
  // Backward compatibility: map to hook/segments/cta
  hook: scenes.find(s => s.scene_type === 'hook')?.audio_text || '',
  segments: scenes.filter(s => s.scene_type === 'body').map(s => s.audio_text),
  cta: scenes.find(s => s.scene_type === 'cta')?.audio_text || ''
};

console.log('Parsed ' + scenes.length + ' scenes. Full script: ' + fullScript.length + ' chars');
console.log('Thumbnail: ' + script.thumbnail_text);

// Strip prompt data, return clean config + script
const { system_prompt, messages, _scene_pipeline, ...cleanConfig } = config;

return [{
  json: {
    ...cleanConfig,
    script: script,
    _scene_pipeline: true
  }
}];
